// GNS 103 — Introduction to Information Literacy
// Question Bank: Mixed MCQ + Fill-in-the-Gap
// MCQ format:  { type: "mcq",  q: "...", opts: ["A","B","C","D"], ans: 0, explanation: "..." }
// FITG format: { type: "fitg", q: "...", ans: "...", explanation: "..." }
// For FITG: ans comparison is case-insensitive, exact spelling required.

const QUESTION_BANK = [
  // ── MCQ ──────────────────────────────────────────────────────────────────
  { type:"mcq", q:"A newspaper is a publication that is issued:", opts:["Daily or Weekly","Monthly","Annually","Biannually"], ans:0, explanation:"Newspapers are periodic publications intended to provide current news and are most commonly published on a daily or weekly schedule to ensure the information remains highly relevant and current." },
  { type:"mcq", q:"Most serials especially journals are acquired through:", opts:["Donation","Subscription","Exchange","Interlibrary loan"], ans:1, explanation:"Because serials and journals are published continuously in successive parts, libraries usually acquire them by paying an ongoing subscription fee to the publisher rather than buying them as one-off purchases." },
  { type:"mcq", q:"One of the factors that affect the production and acquisition of serials is:", opts:["Constant change of serials title","Serials colour","Low cost","Lack of readership"], ans:0, explanation:"Serials are notorious in library management for frequently changing their titles, splitting into multiple parts, or merging with other journals, making cataloging and tracking acquisitions highly complex." },
  { type:"mcq", q:"A major advantage of Electronic Serials is that:", opts:["They can also be accessed from outside the library","They are cheaper","Online articles are difficult to access","None of the above"], ans:0, explanation:"Electronic resources (e-serials) overcome geographical barriers. Patrons can usually log in remotely via proxy servers to read current research without needing to physically visit the library building." },
  { type:"mcq", q:"The Reference unit houses reference materials that are:", opts:["Meant only for consultation","Meant for borrowing","For binding","For reserve"], ans:0, explanation:"Reference materials (like encyclopedias, dictionaries, and atlases) contain quick factual information. They are meant to be consulted briefly inside the library so they are always available to all users, rather than being checked out and taken home." },
  { type:"mcq", q:"_____ are reference materials that give general background information on a topic:", opts:["Dictionaries","Directories","Encyclopedia","Index"], ans:2, explanation:"Encyclopedias are designed to provide comprehensive, general background information and overviews of various subjects, making them the ideal starting point for research." },
  { type:"mcq", q:"_____ is an example of a general encyclopedia:", opts:["Encyclopedia of Biology","Encyclopedia Britannica","Encyclopedia of Agriculture","Encyclopedia of Forestry"], ans:1, explanation:"While options A, C, and D are subject encyclopedias focused on specific disciplines, the Encyclopedia Britannica covers all branches of knowledge, making it a general encyclopedia." },
  { type:"mcq", q:"_____ provide basic data and statistics on topics such as education, health etc and are published annually:", opts:["Abstracts","Indexes","Yearbooks","Handbooks"], ans:2, explanation:"Yearbooks (or annuals) are published every year to summarize the facts, statistics, and major events of the preceding year." },
  { type:"mcq", q:"Bibliography refers to:", opts:["A list of works compiled on some common organizing principle, such as authorship, subject etc.","A book containing lists of names of residents, businesses, organisations etc.","A book of language which provides information regarding the meaning, origin, spellings etc.","Material that gives general background information on a topic."], ans:0, explanation:"A bibliography is systematically compiled to guide users to related literature, usually grouped by author, subject, or publication period." },
  { type:"mcq", q:"The following are advantages of using Non-print resources EXCEPT:", opts:["Aid retention","Preservation","Group instruction","Erratic power supply"], ans:3, explanation:"Non-print resources require equipment and electricity to be accessed. Therefore, an erratic power supply is a major disadvantage, not an advantage." },
  { type:"mcq", q:"Cartographic materials are also known as:", opts:["Maps","Audio-visual materials","Objects","None of the above"], ans:0, explanation:"Cartographic materials refer to any materials representing the whole or part of the earth or any celestial body at any scale. Maps, atlases, and globes are primary examples." },
  { type:"mcq", q:"FUTA library was opened to users on:", opts:["1983","1993","1981","2003"], ans:0, explanation:"The Federal University of Technology, Akure (FUTA) Library was established in 1982 but officially opened its doors to the university community in 1983." },
  { type:"mcq", q:"National Libraries are also known as:", opts:["Virtual libraries","Special libraries","Depository","Archival libraries"], ans:2, explanation:"A National Library serves as the legal depository for a country, meaning publishers are legally mandated to submit copies of every publication produced within the country to it for preservation." },
  { type:"mcq", q:"The word 'library' is derived from a:", opts:["German word","French word","Latin word","Indonesian word"], ans:2, explanation:"The word 'library' is derived from the Latin word 'liber,' which historically referred to the inner bark of trees used as an early writing material." },
  { type:"mcq", q:"The word 'liber' means:", opts:["Book","Library","Literature","All of the above"], ans:0, explanation:"Following its Latin roots, 'liber' directly translates to 'book.' Fundamentally, a library is a collection of books and information resources." },
  { type:"mcq", q:"All these are functions of library EXCEPT:", opts:["Provision of seating and reading facilities","Provision of reference services","Keeping of academic records of students","Provision of users education"], ans:2, explanation:"Keeping academic records (like transcripts and grades) is the administrative function of the University Registry or Academic Affairs department, not the library." },
  { type:"mcq", q:"Travel guide is an example of:", opts:["Biographical reference source","Geographical reference source","Literature search tool","Electronic basic background reference source"], ans:1, explanation:"Travel guides provide detailed information about places, locations, tourism sites, and maps, making them geographical reference materials alongside gazetteers and atlases." },
  { type:"mcq", q:"Types of library can depend on the following EXCEPT:", opts:["Types of services rendered to users","Types of collections in the library","Types of users","Gender of the user"], ans:3, explanation:"Libraries are categorized by their funding body, target audience (children, students, professionals), and the collection type (medical, legal, academic). Gender is not a classification criterion for libraries." },
  { type:"mcq", q:"FUTA library is an example of:", opts:["School library","Public library","Special library","Academic library"], ans:3, explanation:"Any library attached to a post-secondary institution of higher learning (like a university, polytechnic, or college of education) is classified as an academic library." },
  { type:"mcq", q:"A journal can be found in _____ unit of a library:", opts:["Circulation","Reference","Serial","Porters"], ans:2, explanation:"Journals are periodic publications intended to be continued indefinitely. They are managed, housed, and consulted in the Serials unit of a library." },
  { type:"mcq", q:"ISBN means:", opts:["International Standard Book Number","International Standard Bureaucratic Number","International Standard Backlog Number","International Standard Backcode Number"], ans:0, explanation:"ISBN is a unique 10 or 13-digit commercial book identifier assigned to monographic publications (books) to help track, catalog, and purchase them globally." },
  { type:"mcq", q:"Transparency is an example of _____ form of recording knowledge:", opts:["Print","Non-print","Both A and B","None of the above"], ans:1, explanation:"Transparencies are clear sheets of plastic used with overhead projectors. Since they require equipment to be viewed effectively and are not standard paper books, they fall under non-print (audio-visual) resources." },
  { type:"mcq", q:"The library that acts as national information bank is:", opts:["Public library","National library","National Institute of Information","All of the above"], ans:1, explanation:"The National Library acts as the apex library and information bank of a country. It receives copies of all publications via legal deposit and produces the national bibliography." },
  { type:"mcq", q:"A place where we have large number of historical records is called:", opts:["Public library","Archive","National library","School library"], ans:1, explanation:"Archives are special repositories responsible for acquiring, preserving, and making available permanent records, historical documents, and artifacts of enduring value." },
  { type:"mcq", q:"Which unit in the library is responsible for the processing of books?", opts:["Serial unit","Circulation unit","Reference unit","Cataloguing and Classification unit"], ans:3, explanation:"The Cataloguing and Classification unit is where new books are physically and intellectually processed, given call numbers, and entered into the library's catalog so users can find them." },
  { type:"mcq", q:"The maximum number of books that undergraduate students can borrow in the library is:", opts:["Five","Three","Four","Two"], ans:3, explanation:"In many academic libraries, including FUTA's, undergraduates are typically restricted to borrowing a maximum of two books at a time to ensure equitable access to limited resources." },
  { type:"mcq", q:"Charging and discharging are performed in _____ unit of the library:", opts:["Reference","Acquisition","Serial","Circulation"], ans:3, explanation:"The Circulation unit is the primary service point for the lending (charging) and returning (discharging) of library materials, as well as managing user accounts and fines." },
  { type:"mcq", q:"The skills combined in locating and retrieving information is called:", opts:["Information literacy","Information process","Information awareness","Information protocol"], ans:0, explanation:"Information literacy encompasses the core ability to recognize when information is needed and possessing the practical skills to locate, evaluate, and use that information effectively." },
  { type:"mcq", q:"A library without wall is called:", opts:["Digital library","Electronic library","Virtual library","Public library"], ans:2, explanation:"A virtual library provides access to electronic information resources over a network (like the internet), allowing users to access materials remotely from anywhere, effectively removing physical 'walls.'" },
  { type:"mcq", q:"A book borrowed by undergraduate will be for a period of:", opts:["Three weeks","Four weeks","Two weeks","One week"], ans:2, explanation:"Standard loan periods for undergraduate students in university libraries are typically two weeks. This duration allows enough time for study while keeping the book in circulation for others." },
  { type:"mcq", q:"The following are ways of acquiring materials in the library EXCEPT:", opts:["Purchase","Gift","Exchange","Binding"], ans:3, explanation:"Libraries acquire new materials through direct purchases, gifts/donations, and institutional exchanges. Binding is a preservation and maintenance activity, not a method of acquiring new ones." },
  { type:"mcq", q:"The retrieval tool used to locate books on shelves in the library is:", opts:["Library card","Catalogue","Kardex","School identity card"], ans:1, explanation:"The library catalogue (whether a physical card cabinet or an online OPAC) serves as the primary index to the library's collection, providing the necessary call numbers to locate books physically on the shelves." },
  { type:"mcq", q:"'Who is Who' is an example of:", opts:["Literature search tool","Geographical tool","Fact ready tool","Biographical tool"], ans:3, explanation:"'Who's Who' publications are classic biographical reference dictionaries that provide concise personal, educational, and professional details about notable individuals." },
  { type:"mcq", q:"A library that is attached to industrial or corporate organizations is:", opts:["Private library","Public library","Special library","All of the above"], ans:2, explanation:"Special libraries are established by corporations, hospitals, government agencies, or other organizations to serve the highly specific, focused information needs of their employees or researchers." },
  { type:"mcq", q:"A library that is attached to post primary institutions is:", opts:["Academic library","School library","Public library","Special library"], ans:1, explanation:"Libraries situated in primary and secondary (post-primary) educational institutions are designated as school libraries. Academic libraries specifically serve tertiary higher-education institutions." },
  { type:"mcq", q:"All these are allowed in the library for users EXCEPT:", opts:["Borrowing of books","Using of catalogue","Returning consulted books on shelves","Rendering reservation services"], ans:2, explanation:"Library rules universally prohibit users from reshelving books they have consulted. If a user places a book on the wrong shelf, it is essentially 'lost' to the system." },
  { type:"mcq", q:"A book will have at least _____ catalogue entries:", opts:["One","Two","Three","Four"], ans:2, explanation:"In traditional library cataloging, a single book typically requires at least three main access points (cards) for effective retrieval: an Author entry, a Title entry, and a Subject entry." },
  { type:"mcq", q:"Registration of users in the library takes place at:", opts:["Porters unit","Circulation unit","Information Communication and Technology unit","Serial unit"], ans:1, explanation:"The Circulation unit manages all patron accounts. This includes registering new users, issuing library tickets or IDs, and setting up borrowing privileges." },
  { type:"mcq", q:"Advantages of non-prints include the following EXCEPT:", opts:["They aid retention","Group instruction","Preservation","Technology obsolescence"], ans:3, explanation:"Non-print materials (like VHS, cassettes, or old floppy disks) require specific hardware to be used. Technological obsolescence—where the hardware becomes outdated—is a major disadvantage of these formats." },
  { type:"mcq", q:"The reference source that contains synonyms and antonyms with alternate words for identification is called:", opts:["Lexicon","Thesaurus","Dictionary","Special purpose dictionary"], ans:1, explanation:"A thesaurus is a specialized reference tool designed to group words with similar meanings (synonyms) and opposite meanings (antonyms) together, which is incredibly useful for writing and vocabulary building." },
  { type:"mcq", q:"_____ is not a type of library:", opts:["Digital library","Electronic library","Virtual library","None of the above"], ans:3, explanation:"Digital, electronic, and virtual libraries are all recognized modern formats of library systems that manage, store, and provide access to digital resources." },
  { type:"mcq", q:"Selective dissemination of information is a typical library service performed mostly in the:", opts:["Public","Special","Private","Digital"], ans:1, explanation:"Selective Dissemination of Information (SDI) is an intensive, highly customized service where librarians proactively route specific, tailored information to users based on their exact research profiles. This is a hallmark of special libraries." },
  { type:"mcq", q:"ISSN refers to:", opts:["International Standard Serial Number","International Standard Subject Number","International Subject Serial Number","International Standard Sequence Number"], ans:0, explanation:"The correct meaning of ISSN is International Standard Serial Number. It is a unique 8-digit code used to identify serial publications, such as journals, magazines, and newspapers." },
  { type:"mcq", q:"Nigeria 'Who's Who' is an example of a:", opts:["Background reference source","Fact/ready reference source","Biographical reference source","Geographical reference source"], ans:2, explanation:"Any publication titled 'Who's Who' is a biographical dictionary. It provides concise biographical information, life histories, and professional achievements of notable individuals in a specific region or field." },
  { type:"mcq", q:"_____ is a routine task performed in the acquisitions unit:", opts:["Accessioning","Labelling","Cataloguing","Filing"], ans:0, explanation:"The acquisitions unit is responsible for receiving new materials. Once a book is received, it must be 'accessioned'—meaning it is officially recorded in the library's accession register and given a unique serial number before it goes to cataloging." },
  { type:"mcq", q:"A library set up according to owner's subject interest is:", opts:["Personal library","Private library","Special library","Virtual library"], ans:1, explanation:"A private library is owned by an individual and is typically curated based on that specific person's personal interests, hobbies, or professional focus." },
  { type:"mcq", q:"Another name for information literacy is:", opts:["Library literacy","Media literacy","Computer literacy","All of the above"], ans:3, explanation:"Information literacy is an umbrella term. To be truly information literate in the modern world, one must possess library literacy (how to find books), media literacy (how to evaluate news/media), and computer literacy (how to use digital tools)." },
  { type:"mcq", q:"One of the following is a bibliographic part of a book:", opts:["Title","Text","Binding","Dust jacket"], ans:0, explanation:"A book is made up of physical parts (what you can touch) and bibliographic/intellectual parts (the information it contains). The title is a bibliographic element used to identify the book, whereas the binding and dust jacket are purely physical parts." },
  { type:"mcq", q:"_____ is a physical part of a book:", opts:["Table of contents","Half title page","Verso page","Book Cover"], ans:3, explanation:"The book cover is a tangible, physical component designed to protect the pages. The table of contents, half-title page, and verso are structural/bibliographic pages printed inside the book." },
  { type:"mcq", q:"Another term for real object is:", opts:["Realia","Specimen","Cartographic objects","Microforms"], ans:0, explanation:"In library and educational terminology, 'realia' refers to three-dimensional, real-life objects (like coins, tools, artifacts, or textiles) that are used as teaching aids or kept in collections." },
  { type:"mcq", q:"All but one of the following is an example of a graphic material:", opts:["Motion picture","Slide","Still picture","Chart"], ans:0, explanation:"Graphic materials are typically static, two-dimensional visual items (like charts, still pictures, and photographs). A motion picture is classified strictly as an 'audiovisual' resource because it contains moving images and sound." },
  { type:"mcq", q:"An information resource containing list of names of residents or organisations in a place is known as:", opts:["Book list","Index","Directory","Bibliography"], ans:2, explanation:"Directories are ready-reference tools that systematically list individuals, organizations, or businesses along with their contact information and addresses (e.g., a telephone directory)." },
  { type:"mcq", q:"An information resource published in successive parts and contains information is called:", opts:["Newspaper","Newsletter","Magazine","All of the above"], ans:3, explanation:"Any resource that is published continuously in successive issues (daily, weekly, monthly) is a serial publication. Newspapers, newsletters, and magazines all fit this exact definition." },
  { type:"mcq", q:"A book is an information material containing:", opts:["Less than 48 pages","49 pages and above","50 pages and above","Less than 49 pages"], ans:1, explanation:"Based on the standard UNESCO definition used in library science, a printed publication must contain at least 49 pages (excluding the cover) to be officially classified as a book. Anything between 5 and 48 pages is considered a pamphlet." },
  { type:"mcq", q:"_____ is an example of an audio-visual material:", opts:["Still picture","Realia","Slides","Television"], ans:3, explanation:"Audio-visual materials stimulate both the sense of hearing (audio) and sight (visual) simultaneously. Television broadcasts provide both moving images and sound, making it the correct answer." },
  { type:"mcq", q:"The following are aspects of information literacy EXCEPT:", opts:["Media literacy","Computer literacy","Numerical literacy","Print sources of information"], ans:3, explanation:"Literacy refers to a skill or a competency (like being media literate or computer literate). 'Print sources of information' is simply a format or a physical medium (like a book or journal), not a type of literacy skill." },
  { type:"mcq", q:"Secondary information sources are:", opts:["Created from primary materials interpreting original material","Photographs and drama","Created from articles in journals","From reviews and textbooks"], ans:0, explanation:"Secondary sources are written after the fact. They summarize, analyze, evaluate, or interpret primary (original) information materials." },
  { type:"mcq", q:"The term study skill is used for:", opts:["General approaches to learning skills for specific courses of study","Theoretical works on the subject","Retention of lists of information","Efficient note-taking"], ans:0, explanation:"Study skills encompass a broad array of general techniques and approaches (like time management, reading strategies, and note-taking) used to effectively learn and succeed in academic courses." },
  { type:"mcq", q:"The following are types of library EXCEPT:", opts:["National libraries","Public libraries","Private libraries","Education libraries"], ans:3, explanation:"The standard recognized types of libraries are Academic, Public, Special, National, School, and Private. 'Education libraries' is not a standard classification; libraries in educational institutions are simply called Academic or School libraries." },
  { type:"mcq", q:"Readers' Services Division comprises the following units EXCEPT:", opts:["General unit","Circulation unit","Reference unit","Porters/Security Unit"], ans:0, explanation:"The Readers' Services Division handles direct interactions with library patrons. It includes Circulation, Reference, Serials, and the Porters/Security unit. There is no standard department called the 'General unit.'" },
  { type:"mcq", q:"_____ is the major method of acquiring resources in the Library:", opts:["Gift/donations","Inter-library loan","Purchase","All of the above"], ans:2, explanation:"While libraries receive gifts and engage in exchange programs, purchasing (using the library's allocated financial budget to buy specific needed books) is the primary and major method of building a library's core collection." },
  { type:"mcq", q:"Library resources in print format are those information carriers that exist on paper:", opts:["Yes","No","Yes or no","None of the above"], ans:0, explanation:"Print resources explicitly refer to traditional, physical materials where ink is applied to paper, such as books, journals, newspapers, and pamphlets." },
  { type:"mcq", q:"The preliminary pages of a book consist of the following features EXCEPT:", opts:["Fly leaf","Half title page","Title page","Graphic materials"], ans:3, explanation:"Preliminary pages (often called the front matter) include the half-title, title page, copyright page, preface, and table of contents. Graphic materials (like charts or maps) are part of the main text body, not the front matter." },
  { type:"mcq", q:"These resources appeal strictly to the sense of sight EXCEPT:", opts:["Graphic materials","Cartographic materials or maps","Objects","All of the above"], ans:3, explanation:"Graphic materials, cartographic materials (maps), and objects (realia) are all visual materials that appeal strictly to the sense of sight. Therefore, 'all of the above' correctly identifies resources that are strictly visual." },
  { type:"mcq", q:"These information resources combine the qualities of sight and sound in one media:", opts:["Television","Graphics","Books and Radio","Microform"], ans:0, explanation:"Television is an audio-visual medium, meaning it stimulates both the sense of sight (visual moving images) and the sense of hearing (audio sound) simultaneously." },
  { type:"mcq", q:"Miniature mobile storage media are flash drives, memory cards, USB and smart cards:", opts:["Yes","No","Yes and No","Yes or No"], ans:0, explanation:"Flash drives, memory cards, and smart cards are all examples of portable, miniature, solid-state electronic storage devices used to hold and transfer digital information." },
  { type:"mcq", q:"The reference unit is a place in the library where the following materials EXCEPT one are organised for consultation:", opts:["Dictionary","Annuals","Journals","Encyclopedia"], ans:2, explanation:"Dictionaries, annuals (yearbooks), and encyclopedias are classic reference materials housed in the Reference unit. Journals, however, are serial publications and are managed and consulted in the Serials unit." },
  { type:"mcq", q:"Word entries are arranged alphabetically in the following materials EXCEPT:", opts:["Reference sources","Dictionaries","Directories","None of the above"], ans:3, explanation:"Dictionaries, directories, and most standard reference sources (like encyclopedias) arrange their word entries alphabetically. Therefore, there is no exception among the choices." },
  { type:"mcq", q:"These sources provide basic data and statistics on topics such as education, health, sports, personalities or professions and are usually published annually:", opts:["Almanacs and yearbooks","Handbooks, manuals and guides","Literature search reference sources","Abstracts"], ans:0, explanation:"Almanacs and yearbooks are annual publications specifically compiled to provide up-to-date facts, statistics, and a summary of events from the previous year." },
  { type:"mcq", q:"Geographical sources are also known as cartographic sources:", opts:["Yes","No","Yes or No","Yes and No"], ans:0, explanation:"Geographical sources (like maps, atlases, and globes) are created using cartography (the science of drawing maps). Thus, they are frequently referred to interchangeably as cartographic sources." },
  { type:"mcq", q:"Which of the following departments has among its responsibilities the selection and accessioning of information resources bought by or donated to the library?", opts:["Circulation Unit","Acquisition Unit","Reference Unit","Serials Unit"], ans:1, explanation:"The Acquisition unit is the department in a library responsible for selecting, ordering, purchasing, receiving, and accessioning all new library materials." },
  { type:"mcq", q:"A publication issued in successive parts at regular or irregular intervals, intended to be continued indefinitely are:", opts:["Reference materials","Serials","Journals","Documents"], ans:1, explanation:"This is the exact, standard library science definition of a 'serial.' While journals are a type of serial, 'serials' is the broader and correct umbrella term for all such publications." },
  { type:"mcq", q:"Which of these resources is the odd one out?", opts:["Journals","Newsletters","Newspapers","Dictionaries"], ans:3, explanation:"Journals, newsletters, and newspapers are all examples of serial publications. Dictionaries are monographic reference materials, making them the odd one out." },
  { type:"mcq", q:"Which of these resources are published as volumes and issues/numbers, possess ISSN and contain articles?", opts:["Newspaper","Encyclopaedia","Dictionary","Memo"], ans:0, explanation:"Newspapers (alongside journals and magazines) are serials. They are published in successive issues, contain various articles, and are officially identified globally by an International Standard Serial Number (ISSN)." },
  { type:"mcq", q:"Cards in a catalogue cabinet are arranged:", opts:["Chronologically","Serially","Alphabetically","Numerically"], ans:2, explanation:"In traditional physical library card catalogs, the cards (whether sorted by Author, Title, or Subject) are filed and arranged in strict alphabetical order to make searching intuitive for users." },
  { type:"mcq", q:"The Punch is a:", opts:["Weekly journal","Newsletter","Daily journal","Daily newspaper"], ans:3, explanation:"'The Punch' is one of the most widely read and circulated daily print newspapers in Nigeria, making it a classic example of a daily newspaper rather than a journal or newsletter." },
  { type:"mcq", q:"Guardian newspaper belongs to the class of materials called:", opts:["Textbooks","Serials","Journals","Newsletters"], ans:1, explanation:"Any publication that is issued in successive parts (like daily or weekly) and intended to continue indefinitely is categorized broadly as a 'serial.' Therefore, all newspapers fall under the serials classification." },
  { type:"mcq", q:"Undergraduate students are entitled to borrow maximum of _____ while postgraduate students are entitled to _____ number of books:", opts:["2 books and 4 books respectively","3 books and 6 books respectively","2 books and as many books as possible respectively","One book and two books respectively"], ans:0, explanation:"Academic libraries typically grant higher borrowing privileges to postgraduate students because their research demands are more extensive than those of undergraduate students. In FUTA, the standard limit is 2 for undergraduates and 4 for postgraduates." },
  { type:"mcq", q:"All of the following are reference materials EXCEPT:", opts:["Dictionaries","Biographies","Serials","Yearbook"], ans:2, explanation:"Dictionaries, biographies, and yearbooks are ready-reference materials meant for quick fact-checking. Serials (like academic journals and magazines) contain full articles and are managed entirely differently in the Serials unit." },
  { type:"mcq", q:"One of the following is a reason why books may be found in the reserved collection:", opts:["Books are reference materials","Books are a gift to the library","Books are recommended by teaching staff","Books are in bad condition"], ans:2, explanation:"When a lecturer recommends a specific textbook for a course, demand for that book skyrockets. To prevent one student from hoarding it, the library moves it to the 'Reserved Collection' where it can only be borrowed for very short periods." },
  { type:"mcq", q:"Services offered by the reference department include all EXCEPT:", opts:["Answering reference questions","Current awareness services","Referral services","Binding of library materials"], ans:3, explanation:"The reference department is dedicated to user services and information retrieval. Binding (repairing or putting hard covers on books/journals) is a physical preservation task performed by the Bindery or Technical Services department." },
  { type:"mcq", q:"Which of these is not a library service:", opts:["Reprography","Selective Dissemination of Information","Book selling","Current Awareness Services"], ans:2, explanation:"Libraries are fundamentally non-profit service institutions designed to provide free (or tuition-covered) access to information. Selling books for profit is the function of a commercial bookshop, not a library." },
  { type:"mcq", q:"Ondo State Library Board is an example of:", opts:["Archives","State library","National library","Public Library"], ans:3, explanation:"State Library Boards are government bodies established to manage, fund, and operate public libraries that serve the general citizens within that specific state." },
  { type:"mcq", q:"The type of library that serves undergraduates and graduate students, researchers and faculty is called:", opts:["Document center","Academic library","National library","Archives"], ans:1, explanation:"Any library established within a higher education institution (universities, polytechnics, colleges) exists specifically to serve the teaching, learning, and research needs of its students and faculty." },
  { type:"mcq", q:"The unique 10 or 13 digit identification number assigned to editions of books by the publisher is:", opts:["Accession number","ISBN","ISSN","Call number"], ans:1, explanation:"The International Standard Book Number (ISBN) is a unique commercial identifier assigned to monographic publications (books). It historically had 10 digits, but was expanded to 13 digits in 2007." },
  { type:"mcq", q:"'J' is a class mark that represents library materials under:", opts:["Political science","Social science","Science","Military science"], ans:0, explanation:"In the Library of Congress Classification (LCC) scheme, the main class letter 'J' is specifically designated for Political Science." },
  { type:"mcq", q:"The following except one are methods of acquiring information materials in the library:", opts:["Bequest","Accessioning","Inter-library loan","Library exchange"], ans:1, explanation:"Accessioning is not a method of acquiring new materials; rather, it is a processing routine. It involves recording a book into the library's official register and giving it a unique number after it has already been acquired." },
  { type:"mcq", q:"_____ contains bibliographic details of a book including its copyright information:", opts:["Title page","Preface","Verso page","Half title page"], ans:2, explanation:"The verso is the back (left-hand) side of the title page. It traditionally contains the publisher's details, the year of publication, the copyright notice, and the International Standard Book Number (ISBN)." },
  { type:"mcq", q:"_____ is an example of a cartographic material:", opts:["Encyclopedia","Slide","Realia","Map"], ans:3, explanation:"Cartographic materials represent the spatial arrangement of the Earth or other celestial bodies. Maps, atlases, and globes are the most common examples of cartographic resources." },
  { type:"mcq", q:"All but one of the following are advantages of using non-print materials:", opts:["They are good for distance learning programmes","They are not profitable for individualised learning","They are better accessed using electric power","They have large storage capacities"], ans:1, explanation:"This statement is incorrect, making it the exception. Non-print materials (like educational videos, audiobooks, or digital modules) are incredibly beneficial and effective for individualized, self-paced learning." },
  { type:"mcq", q:"_____ is an example of fact/ready reference resource:", opts:["Directories","Abstract","Bibliography","Thesauri"], ans:0, explanation:"Fact or ready reference sources are used to find quick, specific pieces of information without reading long texts. A directory provides specific, ready facts like names, addresses, and organizational contact details." },
  { type:"mcq", q:"A systematic arrangement or list of bibliographic information is called:", opts:["Catalogue","A year book","A manual","A textbook"], ans:0, explanation:"A library catalogue is a systematic, organized, and searchable list of all the bibliographic items (books, journals, multimedia) found in a particular library or group of libraries." },
  { type:"mcq", q:"An information material published in successive parts and intended to continue indefinitely is called:", opts:["A serial","A magazine","A periodical","All of the above"], ans:3, explanation:"'Serial' is the broad overarching term for any publication issued in successive parts. Because magazines and periodicals fall directly under this definition, all the options are correct." },
  { type:"mcq", q:"_____ is not a characteristic of serial:", opts:["It is dynamic","It contains International Standard Book Number","It dwells on specialized subjects","It is written by experts"], ans:1, explanation:"Serials (like academic journals and magazines) are identified by an ISSN (International Standard Serial Number). The ISBN (International Standard Book Number) is reserved strictly for monographic publications (books)." },
  { type:"mcq", q:"_____ is an annual information material containing mostly statistical information on various topics:", opts:["Encyclopedia","Directory","Yearbook","Gazetteer"], ans:2, explanation:"Yearbooks (also known as annuals or almanacs) are reference materials published yearly. They are designed specifically to record the statistics, facts, and major events of the preceding year." },
  { type:"mcq", q:"_____ is an example of a literature search tool:", opts:["Map","Bibliography","Handbook","Dictionary"], ans:1, explanation:"A bibliography is a compiled list of works on a specific subject or by a specific author. It is the primary tool used by students and researchers to find related literature and trace the history of a research topic." },
  { type:"mcq", q:"_____ is a geographical dictionary:", opts:["Gazette","Thesaurus","Bibliography","Gazetteer"], ans:3, explanation:"A gazetteer is a geographical dictionary or directory. It is often used in conjunction with a map or atlas to provide historical, social, and physical information about places and geographical features." },
  { type:"mcq", q:"The display of newly acquired information materials in the library is an example of:", opts:["Reference service","Current awareness service","Selective dissemination of information","Reprographic service"], ans:1, explanation:"Current Awareness Services (CAS) are designed to keep library users up-to-date with the latest acquisitions and developments in their subject fields. Displaying new book arrivals is a classic and simple CAS method." },
  { type:"mcq", q:"One of the following is not a type of index:", opts:["Book index","Alphabetical index","Author index","Numerical index"], ans:3, explanation:"Indexes are typically arranged to help users locate information by language-based access points (such as Alphabetical, Author, or Subject). A purely 'numerical index' is not a standard indexing classification in library science." },
  { type:"mcq", q:"Information materials on technology are classified under:", opts:["S","T","Q","R"], ans:1, explanation:"In the Library of Congress Classification (LCC) system, the main class 'T' is specifically designated for Technology." },
  { type:"mcq", q:"_____ serves as a depository for all publications written about a country:", opts:["Public library","National library","Government library","Legislative library"], ans:1, explanation:"The National Library is legally mandated to serve as the chief depository for a nation. Publishers are required by law to deposit copies of everything they publish with the National Library." },
  { type:"mcq", q:"_____ is a list of the books of a specific author, publisher or on a specific subject:", opts:["Catalogue","Bibliography","Directory","Index"], ans:1, explanation:"A bibliography is a systematically organized list of information sources (books, articles, documents) that share a common element, such as being written by the same author or covering the same subject." },
  { type:"mcq", q:"In Dewey Decimal Classification, 300 stands for:", opts:["Technology","Languages","Social sciences","Generalities"], ans:2, explanation:"The Dewey Decimal Classification (DDC) divides knowledge into 10 main classes using numbers. The 300 class is strictly designated for the Social Sciences." },
  { type:"mcq", q:"A running number carried by each library book indicating when it was acquired into the collection of the library is called:", opts:["International Standard Book Number","Call number","Volume and issue number","Accession Number"], ans:3, explanation:"The accession number is a unique sequential number assigned to each book or material in the exact order it is received and added to the library's collection. It acts as the library's internal inventory tracking number." },
  { type:"mcq", q:"A bulletin issued periodically to a group of defined individuals of a society, business or organization is known as:", opts:["Newspaper","Newsletter","News item","Journals"], ans:1, explanation:"A newsletter is a serial publication produced by an organization, business, or society to share news, updates, and activities specifically with its members or a targeted internal audience." },
  { type:"mcq", q:"A distinguishing factor of a Journal is its:", opts:["Volume and issue numbers","Volume and serial numbers","Volume and book numbers","Volume, serial and book numbers"], ans:0, explanation:"Journals are published sequentially over time. To organize them chronologically and track their publication sequence, they are distinctively assigned volume numbers (usually representing a whole year) and issue numbers." },
  { type:"mcq", q:"The Library of Congress classification scheme is divided into _____ classes:", opts:["21","22","23","24"], ans:0, explanation:"The Library of Congress (LC) Classification scheme uses letters of the alphabet to divide all human knowledge into 21 broad main classes." },
  { type:"mcq", q:"Current Awareness Services include all the following EXCEPT:", opts:["Selective Dissemination of Information","Publication of Current Contents","New Arrivals Lists","Translation Services"], ans:3, explanation:"Current Awareness Services (CAS) inform users about new acquisitions or recent developments in their field. Translation services help overcome language barriers but are not inherently alerting services." },
  { type:"mcq", q:"The name of the Federal University of Technology, Akure Library is:", opts:["FUTA Library","The Library","Albert Ilemobade Library","None of the above"], ans:2, explanation:"The main university library at FUTA was officially named the Albert Ilemobade Library in honor of Professor Albert Ilemobade, a former Vice-Chancellor of the university." },
  { type:"mcq", q:"To evaluate a website, factors to be considered include all BUT:", opts:["Time of download","Authority","Currency","Name of organization/institution the website is affiliated to"], ans:0, explanation:"When evaluating a website for academic research, you use criteria like Currency, Relevance, Authority, Accuracy, and Purpose (the CRAAP test). 'Time of download' is merely a technical issue and does not reflect the academic quality of the information." },
  { type:"mcq", q:"When classifying a book, one can get information about the nature, purpose and scope of the book from its:", opts:["Dedication","Preface","Acknowledgement","Title page"], ans:1, explanation:"The preface is an introductory section written by the author that typically outlines the reason the book was written, its intended audience, its scope, and its general purpose." },
  { type:"mcq", q:"Classification schemes include the following EXCEPT:", opts:["Library of Congress","Dewey decimal Classification","Bloom's Taxonomy Classification","Universal Decimal Classification"], ans:2, explanation:"The Library of Congress, Dewey Decimal, and Universal Decimal are standard library classification schemes used to organize physical books. Bloom's Taxonomy is a pedagogical framework used by teachers to classify learning objectives, not library materials." },
  { type:"mcq", q:"Libraries found in primary and secondary schools are classified as:", opts:["Academic Libraries","School Libraries","Schools' Libraries","Private Libraries"], ans:1, explanation:"In library science terminology, libraries serving primary and secondary education are specifically termed 'School Libraries,' whereas those serving tertiary institutions (universities, polytechnics) are termed 'Academic Libraries.'" },
  { type:"mcq", q:"The Porters' Unit among other things:", opts:["Sees to the security of all library materials","Checks people as they come into the library and go out","Maintains order in the library","All of the above"], ans:3, explanation:"The Porters' Unit (or Security Unit) is stationed at the entrance and exit of the library. Their duties comprehensively involve checking bags to prevent theft, controlling access, and maintaining general security and orderliness." },
  { type:"mcq", q:"All but one of these resources is available in the Multimedia Unit:", opts:["Microform","Video","Cassette","Gazette"], ans:3, explanation:"The Multimedia Unit houses non-print and audio-visual materials like microforms, videos, and cassettes. A gazette is a printed government document or official journal, which is typically found in the Government Publications or Serials unit." },
  { type:"mcq", q:"The library that issues ISSN and ISBN is the:", opts:["Document center","Academic library","National library","Archives"], ans:2, explanation:"In most countries, the National Library is the designated agency responsible for assigning International Standard Book Numbers (ISBN) and International Standard Serial Numbers (ISSN) to publishers." },
  { type:"mcq", q:"Presenting another person's ideas, words, or academic work as your own without proper acknowledgement is known as:", opts:["Copyright infringement","Abstracting","Plagiarism","Paraphrasing"], ans:2, explanation:"Plagiarism is a serious academic offense. It occurs when a student or researcher uses someone else's intellectual property or writing without providing a proper citation or reference to the original author." },
  { type:"mcq", q:"A brief summary of a research article, thesis, or document that helps the reader quickly ascertain the paper's purpose is an:", opts:["Index","Abstract","Appendix","Epilogue"], ans:1, explanation:"An abstract is usually found at the very beginning of a scholarly journal article or thesis. It provides a concise summary of the research methodology, findings, and conclusion, saving researchers time." },
  { type:"mcq", q:"Which of the following search techniques helps to narrow down or broaden a search in an electronic database?", opts:["Truncation","Indexing","Boolean Logic/Operators","Cataloguing"], ans:2, explanation:"Boolean operators (AND, OR, NOT) are used in database searches to connect keywords. 'AND' narrows a search, 'OR' broadens it, and 'NOT' excludes specific terms." },
  { type:"mcq", q:"Which is NOT a valid reason to cite your sources?", opts:["They lend authority to your work","They let readers retrieve sources that you have cited","They give credit to the cited sources","They increase the grade of the author"], ans:3, explanation:"While proper citations might result in a better grade, the fundamental purpose of citation is academic integrity: giving credit to original creators, preventing plagiarism, and allowing readers to verify your facts." },
  { type:"mcq", q:"The largest online professional networking website is:", opts:["Instagram","Facebook","Twitter","LinkedIn"], ans:3, explanation:"LinkedIn was specifically designed for career and business professionals to network, share resumes, and find jobs, making it the largest professional networking site in the world." },
  { type:"mcq", q:"The founder of Facebook is:", opts:["Mark Zuckerberg","Bill Gates","Michael Townsend","Innocent Emagwali"], ans:0, explanation:"Mark Zuckerberg co-founded Facebook in 2004 while he was a student at Harvard University." },
  { type:"mcq", q:"Twitter is a prime example of a _____ service:", opts:["Blogging","Programming","Gaming","Microblogging"], ans:3, explanation:"Microblogging is a broadcast medium that exists in the form of blogging but restricts the content to very short, concise posts (originally 140 characters on Twitter)." },
  { type:"mcq", q:"What are the four critical steps involved in report writing?", opts:["Plan, think, write, and revise","Revise, plan, think, write","Think, plan, write, and revise","Write, plan, revise, and think"], ans:2, explanation:"The logical progression of academic writing is to first think about the problem, plan your outline and research, write the draft, and finally revise and edit the work for submission." },
  { type:"mcq", q:"In APA style, a standard in-text citation consists of:", opts:["Author and year of publication","Publisher and year of publication","Author and cost","Year of publication and publisher"], ans:0, explanation:"The American Psychological Association (APA) format uses the 'author-date' system for in-text citations. For example: (Smith, 2023)." },
  { type:"mcq", q:"All the following are Boolean operators used in database searching EXCEPT:", opts:["WITH","OR","NOT","AND"], ans:0, explanation:"In standard electronic database searching, the three primary Boolean operators are AND, OR, and NOT. 'WITH' is not a standard Boolean logic term." },
  { type:"mcq", q:"Which of the following statements about the internet is true?", opts:["Only experts can publish Web pages","An author's motivations can impact the information that he/she publishes on the Web","Websites don't have authors","Website authors are unbiased"], ans:1, explanation:"Anyone can publish anything on the internet, regardless of their expertise. Therefore, researchers must carefully evaluate a website's author to ensure the information isn't biased." },
  { type:"mcq", q:"The URL address: http://www.epa.gov/climatechange shows that the website:", opts:["Is published by an educational institution","Is trying to sell something","Is used for public awareness","Is published by a government agency"], ans:3, explanation:"In website URLs, the domain extension '.gov' is strictly reserved for official government agencies and entities." },
  { type:"mcq", q:"The URL address: http://ui.edu.ng shows that the website:", opts:["Is published by an educational institution","Is trying to sell something","Is used for public awareness","Is published by a government agency"], ans:0, explanation:"The domain extension '.edu' (often combined with a country code like '.ng' for Nigeria) is restricted globally to accredited educational institutions, such as universities." },
  { type:"mcq", q:"Non-print library resources can broadly be categorized into:", opts:["Audio and visual resources","Audio, Visual, electronic resources and hard copies","Audio, visual, and electronic resources","A-V and their hard copies"], ans:2, explanation:"Non-print resources encompass anything that isn't a traditional paper book. This includes things you listen to (audio), things you watch (visual), and digital formats accessed via computers (electronic)." },
  { type:"mcq", q:"Which of the following would NOT be considered a primary source material?", opts:["A 1975 newspaper on the political situation of Nigeria","A report from a study about students' use of Social media","An article in a journal about original nutritional research","A chapter in a course book that discusses information literacy"], ans:3, explanation:"Primary sources contain raw, original data or firsthand accounts (like a newspaper from the era, or original research findings). A course textbook is a secondary source because it simply compiles and summarizes other people's research." },
  { type:"mcq", q:"Journals are preferred for academic research because:", opts:["They contain outdated information","They contain up-to-date information of a technical nature","They contain popular information","They contain general information for public consumption"], ans:1, explanation:"Because journals are published frequently (monthly or quarterly), they contain the most current, cutting-edge technical research in a field, unlike textbooks which can take years to publish and update." },
  { type:"mcq", q:"Which of these is an example of a subject encyclopedia?", opts:["Encyclopedia Americana","Encyclopedia of Genetic Engineering","Encyclopedia Britannica","Wikipedia"], ans:1, explanation:"While Americana, Britannica, and Wikipedia are general encyclopedias covering all human knowledge, the Encyclopedia of Genetic Engineering restricts its focus entirely to one specific, highly technical field." },
  { type:"mcq", q:"One of these is common to Magazines, Journals, and Newspapers:", opts:["Chapters","ISBN","New Edition","Volume and/or Issue Number"], ans:3, explanation:"Because magazines, journals, and newspapers are all 'Serials' (published continuously in parts), they do not use chapters or editions. Instead, they are organized chronologically by Volume and Issue numbers." },
  { type:"mcq", q:"Which of the following best describes Information literacy?", opts:["The ability to read","The ability to use a computer","The ability to reference","The ability to define an information need and satisfy it"], ans:3, explanation:"Information literacy is a comprehensive skill set. It goes beyond just reading or using a computer; it is the critical ability to realize you need information, know exactly how to locate it, evaluate it, and use it effectively." },
  { type:"mcq", q:"The call number or location number is combination of:", opts:["Subject number and Author number","Subject number and Accession number","Volume number and Issue number","Subject number and ISBN"], ans:0, explanation:"A library call number consists of a class mark (the subject number based on a scheme like LC or Dewey) combined with a book mark (usually an alphanumeric code representing the author's last name, often called a Cutter number)." },
  { type:"mcq", q:"In Dewey Decimal Classification (DDC), the number 300 represents which broad subject area?", opts:["Science","Social Sciences","Literature","History and Geography"], ans:1, explanation:"The DDC divides knowledge into 10 main classes. The 300 class is strictly designated for the Social Sciences, which includes fields like sociology, economics, education, and law." },
  { type:"mcq", q:"The Library of Congress (LC) Classification scheme uses the letter 'R' to represent:", opts:["Agriculture","Medicine","Technology","Education"], ans:1, explanation:"In the LC alphanumeric classification system, the main class 'R' is specifically assigned to Medicine and its related sub-disciplines." },
  { type:"mcq", q:"Which is not true about scholarly journals?", opts:["The articles usually have citations and references","Their articles are often peer-reviewed","The information is usually technical in nature","The articles are usually authored by journalists"], ans:3, explanation:"Scholarly journal articles are written by academics, researchers, and subject experts, not by newspaper journalists. They are peer-reviewed, highly technical, and heavily cited." },
  { type:"mcq", q:"Which of these is NOT part of a citation?", opts:["Author","Title","Date of publication","Call number"], ans:3, explanation:"A standard citation (like APA or MLA) requires the Author, Title, Date, and Publisher to give credit to the source. The Call number is just an internal library location code and has no place in an academic citation." },
  { type:"mcq", q:"Which type of library is primarily funded by the government to serve the general populace of a city or state?", opts:["Academic Library","Special Library","Public Library","Private Library"], ans:2, explanation:"Public libraries are established, supported, and funded by the government (local or state) for the free use of the general public, regardless of their age, profession, or educational background." },
  { type:"mcq", q:"All of the following are classification schemes used in the library EXCEPT:", opts:["DDC","UDC","OPAC","LC"], ans:2, explanation:"DDC (Dewey Decimal), UDC (Universal Decimal), and LC (Library of Congress) are global classification schemes used to assign call numbers to books. OPAC is the computerized search catalogue, not a classification scheme." },
  { type:"mcq", q:"A good report basically has the following sections EXCEPT one:", opts:["Flyer","Title","Table of contents","Introduction"], ans:0, explanation:"Academic and professional reports require a Title page, Table of Contents, and Introduction. A flyer is a promotional piece of paper used for advertising, not a component of formal report writing." },
  { type:"mcq", q:"All except one is not a social media site:", opts:["WhatsApp","OPAC","Facebook","Twitter"], ans:1, explanation:"WhatsApp, Facebook, and Twitter are social networking platforms. OPAC (Online Public Access Catalogue) is a specialized digital database used exclusively to search a library's academic holdings." },
  { type:"mcq", q:"Which of the following is the correct APA Reference list entry for a book?", opts:["Reese G. (2000). Database Programming with JDBC and Java. Beijing: O'Reilly Media","Reese G. Database Programming with JDBC and Java. Beijing: O'Reilly Media (2000).","Database Programming with JDBC and Java. Beijing: O'Reilly Media. Reese G. (2000).","Reese G. (2000). Beijing: O'Reilly Media. Database Programming with JDBC and Java."], ans:0, explanation:"The standard APA citation format for a book is: Author's Last Name, Initial(s). (Year). Title of book. Place of Publication: Publisher." },
  { type:"mcq", q:"The computerised equivalent of the traditional library card cabinet used for locating books is called the:", opts:["Computer Catalogue","Online Public Access Catalogue (OPAC)","Digital Index","Automated Serials System"], ans:1, explanation:"The OPAC (Online Public Access Catalogue) is the modern, digital version of the traditional card catalogue. It allows users to search the library's entire collection electronically using keywords, authors, or titles." },
  { type:"mcq", q:"In scholarly publishing, the process where independent experts evaluate a journal article for quality, validity, and originality before it is accepted for publication is known as:", opts:["Editing","Abstracting","Peer review","Indexing"], ans:2, explanation:"The peer-review process is the gold standard of academic publishing. It ensures that any published research has been vetted and approved by other experts (peers) in that specific field." },
  { type:"mcq", q:"The most appropriate search tool to find the exact page number where a specific topic is discussed within a book is the:", opts:["Table of Contents","Index","Title page","Blurb"], ans:1, explanation:"The index, typically located at the very end of a book, provides an alphabetical list of names, subjects, and concepts mentioned in the text, along with the specific page numbers where they can be found." },
  { type:"mcq", q:"Which classification scheme uses a combination of both letters and numbers (alphanumeric) to classify books?", opts:["Dewey Decimal Classification (DDC)","Library of Congress (LC)","Universal Decimal Classification (UDC)","Bliss Bibliographic Classification"], ans:1, explanation:"Unlike the Dewey Decimal system which uses only numbers, the LC classification scheme uses a combination of letters to denote the main subject class, followed by numbers for subclasses." },
  { type:"mcq", q:"A document of above 49 pages that is bound together at one edge and possesses a distinctive title is defined as a:", opts:["Pamphlet","Serial","Book","Monograph"], ans:2, explanation:"According to the standard definition set by UNESCO for statistical and cataloging purposes, a printed publication must exceed 49 pages (excluding covers) to be classified as a book rather than a pamphlet." },
  { type:"mcq", q:"The legal right granted to an author or creator to control the reproduction and distribution of their original work is called:", opts:["Trademark","Patent","Copyright","Trade secret"], ans:2, explanation:"Copyright is an intellectual property law that protects original works of authorship, ensuring that others cannot legally copy, distribute, or profit from the work without the creator's explicit permission." },
  { type:"mcq", q:"When searching an electronic database, using an asterisk (*) at the end of a word root to find multiple variations is a technique called:", opts:["Wildcarding","Boolean searching","Truncation","Indexing"], ans:2, explanation:"Truncation (stemming) is a search technique that broadens your search to include various word endings and spellings, saving you from having to search for every variation individually." },
  { type:"mcq", q:"A bibliography that attempts to list every single book published within a specific country during a given period is called a:", opts:["Trade bibliography","Subject bibliography","National bibliography","Analytical bibliography"], ans:2, explanation:"Compiled by the National Library (using materials acquired through Legal Deposit), a National Bibliography serves as the official historical record of a nation's publishing output." },
  { type:"mcq", q:"The acronym MLA, which represents a common citation style used heavily in the humanities and literature, stands for:", opts:["Modern Language Association","Modern Linguistic Agency","Manual of Literary Arts","Medical Library Association"], ans:0, explanation:"The MLA style dictates formatting and citation guidelines primarily for disciplines in the humanities, such as English, literature, arts, and philosophy." },
  { type:"mcq", q:"The overwhelming abundance of data, media, and publications available today, which can make it difficult to identify reliable information, is known as:", opts:["Information literacy","Information explosion (or Information overload)","Data mining","Information retrieval"], ans:1, explanation:"The information explosion refers to the rapid, exponential increase in published data (especially since the internet era), which highlights the critical need for students to possess strong information literacy skills." },
  { type:"mcq", q:"To search for a specific phrase exactly as it is written in a search engine, a researcher should enclose the words in:", opts:["Parentheses ( )","Asterisks * *","Quotation marks \" \"","Brackets [ ]"], ans:2, explanation:"Using quotation marks tells the database or search engine to perform a 'Phrase Search.' It will only return results where those exact words appear together in that exact order." },
  { type:"mcq", q:"Which of the following is considered a tertiary source of information?", opts:["A diary entry from 1914","A chemistry textbook","A bibliography of historical books","A research journal article"], ans:2, explanation:"Primary sources are original (the diary). Secondary sources interpret or compile primary sources (the textbook). Tertiary sources are indexes, directories, or bibliographies that organize and point to primary and secondary sources." },
  { type:"mcq", q:"The section of a scholarly journal article that explains the procedures, equipment, and research design used to conduct the study is the:", opts:["Introduction","Abstract","Methodology","Literature Review"], ans:2, explanation:"The methodology section provides a step-by-step breakdown of how the research was conducted. This allows other scientists to replicate the experiment to verify the results." },
  { type:"mcq", q:"Other names of Classification number, include the following except?:", opts:["Call Number","Call Mark","Notation","Notation Mark"], ans:3, explanation:"Classification number can be called Classification number, Call Number, Call Mark, Notation & Class Mark. Notation Mark is odd." },
  { type:"mcq", q:"Information literacy is considered a lifelong learning skill because:", opts:["The library is always open","Technology and information are constantly changing","Universities require it for graduation","Books are expensive"], ans:1, explanation:"Because new information is generated daily and the technologies used to access it evolve rapidly, the ability to find, evaluate, and use information must be a continuous, lifelong practice." },

  // ── FILL-IN-THE-GAP ──────────────────────────────────────────────────────
  { type:"fitg", q:"Encyclopaedia Britannica has only _____ volumes.", ans:"32", explanation:"The final print edition of the Encyclopaedia Britannica (the 15th edition, printed in 2010) consists of 32 volumes." },
  { type:"fitg", q:"A journal belongs to _____ class of library information resources.", ans:"Serials", explanation:"Journals are issued in successive parts at regular intervals and are intended to be continued indefinitely, which is the definition of a serial publication." },
  { type:"fitg", q:"A letter obtained from a user's library that permits him or her to make use of other libraries is known as _____.", ans:"Letter of introduction", explanation:"Academic libraries often require formal proof of your status from your home institution's librarian before granting you access or borrowing privileges as a visiting researcher." },
  { type:"fitg", q:"A short description of a book written at the back cover of the book for promotional purpose is _____.", ans:"Blurb", explanation:"A blurb is a brief promotional text found on the dust jacket or back cover of a book, designed to give the reader an overview and encourage them to read it." },
  { type:"fitg", q:"Users normally keep their personal belongings when entering the Library in the _____.", ans:"Cloak room", explanation:"To prevent theft and the smuggling of library materials, users are required to drop their bags, umbrellas, and other personal belongings in the cloakroom (or baggage area/porters unit) at the entrance." },
  { type:"fitg", q:"Works on a single subject or aspect of a subject are called _____.", ans:"Monographs", explanation:"A monograph is a detailed written study on a single specialized subject or an aspect of it, typically written by a single author or a group of authors. Most standard textbooks are monographs." },
  { type:"fitg", q:"A term used for some geographical reference sources are _____.", ans:"Cartographic sources", explanation:"Cartographic sources broadly encompass maps, globes, atlases, and spatial data that represent geographical information visually." },
  { type:"fitg", q:"Reference sources that provide information on individuals are called _____.", ans:"Biographical reference sources", explanation:"Biographical dictionaries, indexes, and encyclopedias (like 'Who's Who') provide facts, life histories, and achievements of notable people." },
  { type:"fitg", q:"The index consulted by library staff to locate serial materials is _____.", ans:"Kardex", explanation:"The Kardex system is a specialized manual filing cabinet or indexing tool historically used in the Serials unit to keep track of the receipt of journal issues and serial subscriptions." },
  { type:"fitg", q:"A paper designed to cover a published book is called _____.", ans:"Dust jacket", explanation:"The dust jacket (sometimes called a book jacket or dust cover) is the detachable outer paper cover used to protect the hard binding of a book and usually displays promotional blurbs and the author's biography." },
  { type:"fitg", q:"An information material containing between five and forty-eight pages is known as a _____.", ans:"Pamphlet", explanation:"According to the standard definition set by UNESCO, a publication that is non-periodical and contains at least 5 but no more than 48 pages (exclusive of the cover pages) is classified as a pamphlet rather than a book." },
  { type:"fitg", q:"International Institute of Tropical Agriculture (IITA) Library, Ibadan is an example of a _____.", ans:"Special library", explanation:"The IITA Library serves a specific research institute focused on agricultural development. Libraries attached to research institutes, corporations, hospitals, or government agencies are classified as special libraries." },
  { type:"fitg", q:"Providing information on where to get specific information materials is part of the function of the _____ unit.", ans:"Reference", explanation:"The Reference unit is the primary point of contact for assisting users. Librarians in this unit answer queries, guide users on how to use catalogs, and direct them to the appropriate resources or other libraries." },
  { type:"fitg", q:"_____ is an example of a miniature storage medium.", ans:"Memory card", explanation:"Memory cards (like SD cards) and USB flash drives are highly portable, miniature electronic storage media used to hold large amounts of digital files, documents, and multimedia." },
  { type:"fitg", q:"_____ libraries are owned by an individual.", ans:"Private", explanation:"Private libraries (also known as personal libraries) are established, owned, and maintained by individuals for their own personal use, hobbies, or research." },
  { type:"fitg", q:"The _____ library assigns International Standard Book Number.", ans:"National", explanation:"In most countries, the National Library is the sole agency responsible for issuing ISBNs to authors and publishers to maintain a standardized bibliographic record of the country's publications." },
  { type:"fitg", q:"ISSN means _____.", ans:"International Standard Serial Number", explanation:"The ISSN is an internationally accepted 8-digit code used to uniquely identify serial publications (like journals, magazines, and newspapers)." },
  { type:"fitg", q:"The _____ is actively involved in inter-library lending schemes in a country.", ans:"National Library", explanation:"The National Library often acts as the apex or coordinating body for library networks within a country, facilitating inter-library loans and resource sharing among different library systems." },
  { type:"fitg", q:"_____ is the unit where users are registered.", ans:"Circulation unit", explanation:"The Circulation unit is responsible for all patron records. This includes the registration of new library users, issuing library cards, and handling the check-out and return of books." },
  { type:"fitg", q:"_____ unit is responsible for maintaining security in the library.", ans:"Porters", explanation:"The Porters' unit (or security/cloakroom unit) is stationed at the entrance and exit of the library to check bags, ensure unauthorized materials aren't taken out, and maintain general order." },
  { type:"fitg", q:"_____ takes place when a library trades some of its materials for the ones it lacks with another library that would have need for them.", ans:"Library exchange", explanation:"Library exchange is a mutual agreement between institutions to trade duplicate or unwanted materials with each other to enrich both collections without direct financial cost." },
  { type:"fitg", q:"_____ are the commonest forms of information carriers.", ans:"Books", explanation:"Despite the rise of digital media, traditional printed books remain the most fundamental, widely recognized, and common format for carrying and storing detailed academic information in libraries." },
  { type:"fitg", q:"_____ is the edge of the book that holds the printed papers.", ans:"spine", explanation:"The spine is the bound, outer edge of a book that holds all the pages together. It typically displays the book's title, author, and library call number so the book can be identified on a shelf." },
  { type:"fitg", q:"With advancing technologies, OPAC, MARC and others, library users can be _____.", ans:"Any one in the world", explanation:"Online Public Access Catalogues (OPACs) are accessible over the internet. This means that instead of being restricted to physical visitors inside the building, anyone in the world with an internet connection can search the library's holdings." },
  { type:"fitg", q:"_____ treats specific subjects like agriculture, medicine etc.", ans:"Subject encyclopedia", explanation:"While a general encyclopedia (like Britannica) covers all areas of knowledge, a subject encyclopedia provides detailed, comprehensive background information restricted to one specific field or discipline." },
  { type:"fitg", q:"A paper designed to cover a published book is called _____.", ans:"Dust jacket", explanation:"The dust jacket is the removable paper cover on a hardcover book. It usually features the 'blurb'—a short promotional summary of the book's contents to entice readers." },
  { type:"fitg", q:"_____ is a list of the books of a specific author, publisher or on a specific subject.", ans:"Bibliography", explanation:"A bibliography is systematically organized to list information sources that share a common element, such as being written by the same author or covering the same subject." },
  { type:"fitg", q:"_____ are good source of primary information.", ans:"Journals", explanation:"Academic and scientific journals are the main vehicles for publishing new, original research findings, making them one of the most important primary sources of information in the academic world." },
  { type:"fitg", q:"The final research report or project submitted for the award of a doctorate degree is officially called a _____.", ans:"Thesis", explanation:"In academic terminology, a thesis or dissertation is the culmination of original research required to earn higher degrees (Master's or Ph.D.). These are highly valuable primary sources of information." },
  { type:"fitg", q:"A compilation of maps and geographical charts bound together in a single volume is called an _____.", ans:"Atlas", explanation:"While a map is a single geographical representation, an atlas is a comprehensive collection of various maps (political, physical, thematic) published together as a book." },
  { type:"fitg", q:"_____ is the process of critically evaluating information sources to determine their accuracy, currency, and reliability.", ans:"Information evaluation", explanation:"As part of information literacy, users must evaluate sources to ensure the information they are using for their academic research is credible, unbiased, and up-to-date." },
  { type:"fitg", q:"A _____ is a specialized library located within a corporate organization, hospital, or research institute.", ans:"Special library", explanation:"Special libraries are designed strictly to serve the specialized information and research needs of the staff or members of the parent organization, rather than the general public or students." },
  { type:"fitg", q:"The systematic arrangement of books on the library shelves based on their subject matter is known as _____.", ans:"Classification", explanation:"Classification is the process of translating the subject content of a book into a standardized code (like the Library of Congress Classification) so that books on the same subject are shelved together." },
  { type:"fitg", q:"The _____ classification scheme uses numbers exclusively from 000 to 999 to classify human knowledge.", ans:"Dewey Decimal", explanation:"Created by Melvil Dewey, the DDC uses a strict numerical system to organize library books into 10 main disciplines." },
  { type:"fitg", q:"The alphabetical list of specific topics, names, and concepts along with their page numbers, usually located at the very end of a book, is the _____.", ans:"Index", explanation:"The index is a navigational tool that allows a reader to instantly find exactly which page a specific topic is discussed on without reading the whole book." },
  { type:"fitg", q:"_____ is an umbrella term for the skills required to recognize when information is needed, and to locate, evaluate, and effectively use that information.", ans:"Information Literacy", explanation:"Information literacy is the ultimate goal of the GNS 103 course. It empowers students to become independent, critical researchers in the digital age." },
  { type:"fitg", q:"The list of difficult, technical, or unfamiliar words along with their definitions found at the back of a book is called a _____.", ans:"Glossary", explanation:"A glossary acts as a mini-dictionary specific to the book it is printed in, helping the reader understand the specialized terminology used by the author." },
  { type:"fitg", q:"The introductory section of a book where the author explains their reasons for writing the book and its intended audience is called the _____.", ans:"Preface", explanation:"The preface gives the reader insight into the author's thought process, the scope of the work, and the methodology used to write it." },
  { type:"fitg", q:"A _____ is a continuous publication issued in parts (daily, weekly, or monthly) that is intended to go on indefinitely.", ans:"Serial", explanation:"'Serial' is the broad umbrella term in library science that covers journals, magazines, newspapers, and annuals." },
  { type:"fitg", q:"The eight-digit code used to uniquely identify a serial publication globally is the _____.", ans:"ISSN", explanation:"Just as books have an ISBN, serials are tracked internationally using the ISSN (International Standard Serial Number) to avoid confusion between journals with similar names." },
  { type:"fitg", q:"A formal agreement where two different libraries borrow materials from each other to satisfy their users' requests is called _____.", ans:"Inter-library loan", explanation:"Because no single library can own every book in the world, libraries form networks to share resources through inter-library loans." },
  { type:"fitg", q:"_____ sources of information are original, uninterpreted records or firsthand accounts of events.", ans:"Primary", explanation:"Primary sources are the raw materials of research, such as diaries, interview transcripts, original lab data, and government treaties." },
  { type:"fitg", q:"Textbooks, review articles, and biographies that summarize and interpret original research are classified as _____ sources of information.", ans:"Secondary", explanation:"Secondary sources are one step removed from the original event. They analyze, synthesize, and explain primary data." },
  { type:"fitg", q:"Reference materials like bibliographies, indexes, and directories that compile and organize primary and secondary sources are known as _____ sources.", ans:"Tertiary", explanation:"Tertiary sources do not provide new information; they act as signposts or guides to help researchers locate primary and secondary information." },
  { type:"fitg", q:"The alphanumeric code placed on the spine of a library book to indicate its exact location on the shelves is called the _____.", ans:"Call number", explanation:"The call number combines the subject classification mark and the author's cutter number to give the book a unique 'address' in the library." },
  { type:"fitg", q:"Three-dimensional objects, artifacts, or real-life specimens kept in a library for educational purposes are referred to as _____.", ans:"Realia", explanation:"Realia brings real-world objects (like ancient coins, biological specimens, or cultural artifacts) into the learning environment for hands-on observation." },
  { type:"fitg", q:"The _____ page is typically the first printed page of a book and contains only the main title of the work, without the author or publisher's details.", ans:"Half-title", explanation:"The half-title page precedes the main title page and serves as a simple introduction to the book's text." },
  { type:"fitg", q:"The main campus library at the Federal University of Technology, Akure is named the _____ Library.", ans:"Albert Ilemobade", explanation:"The library was named in honor of Professor Albert Ilemobade, a former Vice-Chancellor who played a significant role in the university's development." },
  { type:"fitg", q:"When a library user places their bags, umbrellas, and non-essential items in a designated security area before entering the reading halls, they are using the _____.", ans:"Cloak room", explanation:"To maintain security and prevent the theft of books, users are required to deposit their personal belongings at the entrance cloakroom under the supervision of the library porters." },
  { type:"fitg", q:"The _____ library assigns International Standard Book Number to publishers.", ans:"National", explanation:"In Nigeria, the National Library issues ISBNs to authors and publishers to maintain a centralized record of everything published in the country." },
  { type:"fitg", q:"Before the invention of paper, early Egyptians recorded information on a material made from reeds known as _____.", ans:"Papyrus", explanation:"Papyrus was one of the earliest forms of writing materials, created by the ancient Egyptians from the pith of the papyrus plant. The modern word 'paper' is derived from it." },
  { type:"fitg", q:"In academic research, information materials that are not commercially published or widely distributed (such as government working papers, technical reports, and unpublished theses) are collectively referred to as _____ literature.", ans:"Grey", explanation:"'Grey literature' refers to research produced by organizations outside of the traditional commercial or academic publishing and distribution channels. It is highly valuable but can be difficult to track down." },
  { type:"fitg", q:"The _____ classification scheme uses a combination of both letters and numbers (alphanumeric) to classify books.", ans:"Library of Congress", explanation:"Unlike the Dewey Decimal system which uses only numbers, the LC classification scheme uses a combination of letters and numbers, allowing for a much larger and more specific expansion of topics." },
  { type:"fitg", q:"_____ is the library software used in the FUTA library.", ans:"SLAM", explanation:"SLAM (System for Library Automation and Management) is the specific digital software package deployed by the FUTA University Library to manage its OPAC, digital resources, and patron databases." },
  { type:"fitg", q:"A blank leaf found at the beginning or end of a book is called a _____.", ans:"Flyleaf", explanation:"A flyleaf is a blank page inserted by the binder at the front and back of a book. It helps protect the printed pages and adds structural integrity to the book's cover." },
  { type:"fitg", q:"The section at the back of a book that contains supplementary information, raw data, or extra charts that are helpful but not essential to the main text is the _____.", ans:"Appendix", explanation:"Appendices provide extra context without cluttering the main chapters of the book." },
];
